const raw = $input.first().json;
const body = raw.body ?? raw;

function pick(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

const issue = body.data?.issue ?? body.issue ?? {};
const event = body.data?.event ?? body.event ?? {};

const title = pick(
  issue.title,
  body.message,
  event.title,
  event.message,
  body.culprit,
  'Sentry alert'
);
const level = pick(issue.level, body.level, event.level, 'error');
const project = pick(
  issue.project?.name,
  body.project_name,
  body.project,
  issue.project?.slug,
  'unknown'
);
const url = pick(
  issue.web_url,
  issue.permalink,
  body.url,
  event.web_url,
  ''
);
const rule = pick(
  body.triggering_rules?.[0],
  body.data?.triggered_rule,
  body.action,
  'alert'
);
const env = pick(event.environment, body.environment, issue.environment, '');

const lines = [
  `🚨 Sentry ${level}`,
  `Project: ${project}`,
  `Rule: ${rule}`,
  title.slice(0, 280),
];
if (env) lines.push(`Env: ${env}`);
if (url) lines.push(url);

const phone = String($env.ADMIN_ALERT_PHONE || '').trim();
if (!phone) {
  throw new Error('ADMIN_ALERT_PHONE is not set in n8n env');
}

return [{
  json: {
    text: lines.join('\n'),
    chatId: phone.replace('+', '') + '@c.us',
    wahaUrl: $env.WAHA_API_URL,
    wahaKey: $env.WAHA_API_KEY,
  }
}];
